function flattenShips() {
    const tiers = ["tier6", "tier7"];

    for (const tier of tiers) {
        if (SHIP_SELECTION.vanilla.hasOwnProperty(tier)) {
            staticMemory.FLATTENED_SHIPS.push(...SHIP_SELECTION.vanilla[tier].map(ship => ({ type: String(ship[0]), tier })));
        }
    }
}

flattenShips();

console.log(staticMemory.FLATTENED_SHIPS);

const shipCodeToName = {};
const shipNameToCode = {};
for (const shipTree of Object.values(SHIPS)) {
    for (const [code, {name}] of Object.entries(shipTree)) {
        shipCodeToName[code] = name;
        shipNameToCode[name] = Number(code);
    }
}

for (let [key, val] of Object.entries(SPECIAL_SHIPS)) {
    SPECIAL_SHIPS[key] = shipNameToCode[val];
}

const checkLegacySpeedster = code => (!ALLOW_LEGACY_TURN && code === SPECIAL_SHIPS.LegacySpeedster) ? SPECIAL_SHIPS.ASpeedster : code;

const getInputShipCode = ship => {
    let code = Number(ship);
    if (isNaN(code)) {
        if (typeof ship === "string") {
            ship = ship.trim();
            if (ship.length > 0) {
                code = shipNameToCode[ship];
                return code ? checkLegacySpeedster(code) : null;
            }
        }
        return null;
    }
    if (shipCodeToName[code]) {
        return checkLegacySpeedster(code);
    }
    return null;
};

staticMemory.requireShip = getInputShipCode(staticMemory.requireShip);
const STARTING_SHIP_CODE = staticMemory.requireShip || getInputShipCode(STARTING_SHIP);

