const turnToSpectator = (ship, lastShip = null) => {
    ship.spectating = {
        value: true,
        lastShip: lastShip || (ship.type === SPECIAL_SHIPS.Spectator ? (ship.spectating?.lastShip || 101) : ship.type)
    }
    ship.set({type: SPECIAL_SHIPS.Spectator, collider: false, crystals: 0});
    if (ALLOW_LEGACY_TURN && (ship.type === SPECIAL_SHIPS.ASpeedster || ship.type === SPECIAL_SHIPS.LegacySpeedster)) {
        deselectedSpeedsterProcedure(ship);
    }
}

function getNextShipType(currentShipType) {
    const currentShipIndex = staticMemory.FLATTENED_SHIPS.findIndex(ship => ship.type === String(currentShipType));

    if (currentShipIndex === -1) {
        console.warn("Ship type not found in SHIP_SELECTION:", currentShipType);
        return null;
    }

    const nextShipIndex = (currentShipIndex + 1) % staticMemory.FLATTENED_SHIPS.length;
    return staticMemory.FLATTENED_SHIPS[nextShipIndex].type;
}

function getPrevShipType(currentShipType) {
    const currentShipIndex = staticMemory.FLATTENED_SHIPS.findIndex(ship => ship.type === String(currentShipType));

    if (currentShipIndex === -1) {
        console.warn("Ship type not found in SHIP_SELECTION:", currentShipType);
        return null;
    }
    const prevShipIndex = (currentShipIndex - 1 + staticMemory.FLATTENED_SHIPS.length) % staticMemory.FLATTENED_SHIPS.length;
    return staticMemory.FLATTENED_SHIPS[prevShipIndex].type;
}


function switchShip(ship, direction = 'next') {
    if (staticMemory.requireShip) {
        return fleetingMessage(ship, "Required ship is enabled");
    }
    if (ship.spectating.value) {
        return fleetingMessage(ship, "You are spectating");
    }

    let newType;
    if (direction === 'next') {
        newType = getNextShipType(ship.type);
    } else if (direction === 'prev') {
        newType = getPrevShipType(ship.type);
    } else {
        console.warn("Invalid direction:", direction);
        return;
    }

    if (newType === null) {
        return;
    }

    let newStats = 66666666;
    if (ship.custom.keep_maxed) {
        newStats = Math.min(ship.stats, 88888888);
    }

    if (ALLOW_LEGACY_TURN) {
        if (Number(newType) === SPECIAL_SHIPS.ASpeedster) {
            ship.custom.speedsterType = "new";
            selectedSpeedsterProcedure(ship, true);
        } else if (ship.type === SPECIAL_SHIPS.ASpeedster || ship.type === SPECIAL_SHIPS.LegacySpeedster) {
            deselectedSpeedsterProcedure(ship);
        }
    }

    ship.set({
        type: Number(newType),
        stats: newStats,
        shield: 999,
        crystals: staticMemory.GEM_CAPS[Number(newType) / 100 >> 0]
    });

    if (ship.custom._shipSelectOpen) {
        SHIP_TREE_PANEL.updateShipHighlight(ship, newType);
    } else {
        ship.custom.previousShipType = newType;
    }
}


